class ChampionInfer(BasicInfer):
    def __init__(self, bentoml_url: str):
        self.bentoml_url = bentoml_url

    def inferer(self):
        return SimpleInferer()

    def pre_transforms(self, data=None):
        return [LoadImaged(keys="image"), EnsureChannelFirstd(keys="image")]

    def post_transforms(self, data=None):
        return [Activationsd(keys="pred"), AsDiscreted(keys="pred", argmax=True)]

    def run_infer(self, request, callbacks=None):
        # Load volume, call BentoML REST endpoint, return mask
        from minivess.serving.inference_client import RemoteInferenceClient
        client = RemoteInferenceClient(self.bentoml_url)
